#' Frequencies
#'
#' Summarize the counts or proportions of a categorical variable. Draws 
#' side-by-side, stacked, or 100\% stacked bar charts, pie or donut charts, 
#' and Pareto charts, with percentage or count labels. The Statistics panel 
#' reports chi-square tests, standardized residuals, proportion comparisons, 
#' and counts. Group and facet to break the counts down further.
#' 
#' @param annotationsJson .
#' @param chartSnapshot .
#' @param clientBundleHash .
#' @param data .
#' @param errorBarType .
#' @param exportPath .
#' @param exportRequest .
#' @param facetVar .
#' @param freqPosition .
#' @param freqStat .
#' @param graphType .
#' @param groupVar .
#' @param paletteLibrary .
#' @param showDataPoints .
#' @param styleLibrary .
#' @param styleStamp .
#' @param summaryFunc .
#' @param var .
#' @param chartSpec .
#' @return A results object containing:
#' \tabular{llllll}{
#'   \code{results$widget} \tab \tab \tab \tab \tab a html \cr
#'   \code{results$exportStatus} \tab \tab \tab \tab \tab a html \cr
#' }
#'
#' @export
freqplotbuilder <- function(
    annotationsJson = "",
    chartSnapshot = "",
    clientBundleHash = "",
    data,
    errorBarType = "se",
    exportPath = "",
    exportRequest = "",
    facetVar,
    freqPosition = "dodge",
    freqStat = "count",
    graphType = "bar",
    groupVar,
    paletteLibrary = "",
    showDataPoints = FALSE,
    styleLibrary = "",
    styleStamp = FALSE,
    summaryFunc = "mean",
    var,
    chartSpec = "") {

    if ( ! requireNamespace("jmvcore", quietly=TRUE))
        stop("freqplotbuilder requires jmvcore to be installed (restart may be required)")

    if ( ! missing(facetVar)) facetVar <- jmvcore::resolveQuo(jmvcore::enquo(facetVar))
    if ( ! missing(groupVar)) groupVar <- jmvcore::resolveQuo(jmvcore::enquo(groupVar))
    if ( ! missing(var)) var <- jmvcore::resolveQuo(jmvcore::enquo(var))
    if (missing(data))
        data <- jmvcore::marshalData(
            parent.frame(),
            `if`( ! missing(facetVar), facetVar, NULL),
            `if`( ! missing(groupVar), groupVar, NULL),
            `if`( ! missing(var), var, NULL))

    for (v in facetVar) if (v %in% names(data)) data[[v]] <- as.factor(data[[v]])
    for (v in groupVar) if (v %in% names(data)) data[[v]] <- as.factor(data[[v]])
    for (v in var) if (v %in% names(data)) data[[v]] <- as.factor(data[[v]])

    options <- freqplotbuilderOptions$new(
        annotationsJson = annotationsJson,
        chartSnapshot = chartSnapshot,
        clientBundleHash = clientBundleHash,
        errorBarType = errorBarType,
        exportPath = exportPath,
        exportRequest = exportRequest,
        facetVar = facetVar,
        freqPosition = freqPosition,
        freqStat = freqStat,
        graphType = graphType,
        groupVar = groupVar,
        paletteLibrary = paletteLibrary,
        showDataPoints = showDataPoints,
        styleLibrary = styleLibrary,
        styleStamp = styleStamp,
        summaryFunc = summaryFunc,
        var = var,
        chartSpec = chartSpec)

    analysis <- freqplotbuilderClass$new(
        options = options,
        data = data)

    analysis$run()

    analysis$results
}

